import collections

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)
        if root_i != root_j:
            self.parent[root_j] = root_i
            return True
        return False

def smallestStringWithSwaps(s: str, pairs: list[list[int]]) -> str:
    n = len(s)
    uf = UnionFind(n)

    for i, j in pairs:
        uf.union(i, j)

    # Group characters and their original indices by their root parent
    # Each root represents a connected component where characters can be freely swapped
    components = collections.defaultdict(lambda: {'indices': [], 'chars': []})
    for i in range(n):
        root = uf.find(i)
        components[root]['indices'].append(i)
        components[root]['chars'].append(s[i])

    result = [''] * n

    # For each component, sort the characters and the indices independently
    # Then assign the sorted characters to the sorted indices
    for root in components:
        indices = components[root]['indices']
        chars = components[root]['chars']

        indices.sort()  # Sort indices to determine placement order
        chars.sort()    # Sort characters to get the lexicographically smallest arrangement

        for i in range(len(indices)):
            result[indices[i]] = chars[i]

    return "".join(result)
